// i18n.js - 初始化i18next
$(document).ready(function() {
    i18next
        .use(i18nextHttpBackend)
        .use(i18nextBrowserLanguageDetector)
        .init({
            lng: 'en', // 默认语言
            fallbackLng: 'en',
            debug: false,
            backend: {
                loadPath: 'locales/{{lng}}.json'
            },
            detection: {
                order: ['localStorage', 'navigator', 'htmlTag'],
                caches: ['localStorage']
            }
        }, function(err, t) {
            // 初始化jquery-i18next
            jqueryI18next.init(i18next, $, {
                tName: 't', // --> appends $.t = i18next.t
                i18nName: 'i18n', // --> appends $.i18n = i18next
                handleName: 'localize', // --> appends $(selector).localize(opts);
                selectorAttr: 'data-i18n', // selector for translating elements
                targetAttr: 'i18n-target', // data-() attribute to grab target element to translate (if different than itself)
                optionsAttr: 'i18n-options', // data-() attribute that contains options, will load/set if useOptionsAttr = true
                useOptionsAttr: false, // see optionsAttr
                parseDefaultValueFromContent: true // parses default values from content ele.val or ele.text
            });

            // 翻译页面
            $('body').localize();

            // 设置placeholder
            $('input[placeholder]').each(function() {
                var key = $(this).attr('placeholder');
                if (key === 'Please enter a value.') {
                    $(this).attr('placeholder', i18next.t('pleaseEnterValue'));
                }
            });

            // 更新DataTable语言
            updateDataTableLanguage();
        });

    // 语言切换函数
    window.changeLanguage = function(lng) {
        i18next.changeLanguage(lng, function(err, t) {
            $('body').localize();
            // 设置placeholder
            $('input[placeholder]').each(function() {
                var key = $(this).attr('placeholder');
                if (key === 'Please enter a value.' || key === i18next.t('pleaseEnterValue')) {
                    $(this).attr('placeholder', i18next.t('pleaseEnterValue'));
                }
            });
            updateDataTableLanguage();
            localStorage.setItem('i18nextLng', lng);
        });
    };

    // 更新DataTable语言
    function updateDataTableLanguage() {
        var table = $('#myTable').DataTable();
        table.settings()[0].oLanguage = {
            search: "",
            searchPlaceholder: i18next.t('searchPlaceholder'),
            "emptyTable": i18next.t('emptyTable')
        };
        table.draw();
    }
});

// i18n.js - 初始化i18next
$(document).ready(function() {
    i18next
        .use(i18nextHttpBackend)
        .use(i18nextBrowserLanguageDetector)
        .init({
            lng: 'en', // 默认语言
            fallbackLng: 'en',
            debug: false,
            backend: {
                loadPath: 'locales/{{lng}}.json'
            },
            detection: {
                order: ['localStorage', 'navigator', 'htmlTag'],
                caches: ['localStorage']
            }
        }, function(err, t) {
            // 初始化jquery-i18next
            jqueryI18next.init(i18next, $, {
                tName: 't', // --> appends $.t = i18next.t
                i18nName: 'i18n', // --> appends $.i18n = i18next
                handleName: 'localize', // --> appends $(selector).localize(opts);
                selectorAttr: 'data-i18n', // selector for translating elements
                targetAttr: 'i18n-target', // data-() attribute to grab target element to translate (if different than itself)
                optionsAttr: 'i18n-options', // data-() attribute that contains options, will load/set if useOptionsAttr = true
                useOptionsAttr: false, // see optionsAttr
                parseDefaultValueFromContent: true // parses default values from content ele.val or ele.text
            });

            // 翻译页面
            $('body').localize();

            // 设置placeholder
            $('input[placeholder]').each(function() {
                var key = $(this).attr('placeholder');
                if (key === 'Please enter a value.') {
                    $(this).attr('placeholder', i18next.t('pleaseEnterValue'));
                }
            });

            // 更新DataTable语言
            updateDataTableLanguage();
        });

    // 语言切换函数
    window.changeLanguage = function(lng) {
        i18next.changeLanguage(lng, function(err, t) {
            $('body').localize();
            // 设置placeholder
            $('input[placeholder]').each(function() {
                var key = $(this).attr('placeholder');
                if (key === 'Please enter a value.' || key === i18next.t('pleaseEnterValue')) {
                    $(this).attr('placeholder', i18next.t('pleaseEnterValue'));
                }
            });
            updateDataTableLanguage();
            localStorage.setItem('i18nextLng', lng);
        });
    };

    // 更新DataTable语言
    function updateDataTableLanguage() {
        var table = $('#myTable').DataTable();
        table.settings()[0].oLanguage = {
            search: "",
            searchPlaceholder: i18next.t('searchPlaceholder'),
            "emptyTable": i18next.t('emptyTable')
        };
        table.draw();

        // 更新按钮文本
        var buttons = table.buttons();
        buttons[0][0].text = i18next.t('addNewItemButton');
        buttons[0][1].text = i18next.t('saveDataButton');
        buttons[0][2].text = i18next.t('newDataButton');
        buttons[0][3].text = i18next.t('loadDataButton');
        table.buttons().draw();
    }
});
